import React from 'react';

/**
 * EmployeeCard component for displaying individual employee information
 * @param {Object} props - Component props
 * @param {Object} props.employee - Employee data object
 * @param {Function} props.onEdit - Callback function for editing employee
 * @param {Function} props.onDelete - Callback function for deleting employee
 */
const EmployeeCard = ({ employee, onEdit, onDelete }) => {
  /**
   * Format date to readable string
   * @param {string} dateString - Date string to format
   * @returns {string} Formatted date
   */
  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  /**
   * Handle edit button click
   */
  const handleEdit = () => {
    onEdit(employee);
  };

  /**
   * Handle delete button click
   */
  const handleDelete = () => {
    onDelete(employee._id);
  };

  return (
    <div className="employee-card">
      <div className="employee-info">
        <h3 className="employee-name">{employee.name}</h3>
        <div className="employee-details">
          <div className="employee-detail">
            <span className="detail-label">Role:</span>
            <span className="detail-value">{employee.role}</span>
          </div>
          <div className="employee-detail">
            <span className="detail-label">Department:</span>
            <span className="detail-value">{employee.department}</span>
          </div>
          <div className="employee-detail">
            <span className="detail-label">Email:</span>
            <span className="detail-value">{employee.email}</span>
          </div>
          {employee.phone && (
            <div className="employee-detail">
              <span className="detail-label">Phone:</span>
              <span className="detail-value">{employee.phone}</span>
            </div>
          )}
          <div className="employee-detail">
            <span className="detail-label">Hire Date:</span>
            <span className="detail-value">{formatDate(employee.hireDate)}</span>
          </div>
        </div>
      </div>

      <div className="employee-actions">
        <button
          className="btn btn-edit"
          onClick={handleEdit}
          aria-label={`Edit ${employee.name}`}
        >
          Edit
        </button>
        <button
          className="btn btn-delete"
          onClick={handleDelete}
          aria-label={`Delete ${employee.name}`}
        >
          Delete
        </button>
      </div>
    </div>
  );
};

export default EmployeeCard;
